975	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
976	                {
977	                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
978	                    {
979	                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
980	                    }
981	                    else
982	                    {
983	                        nn_dup_u8_u16_reordered
984	                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
985	                    }
986	                    pBuffer += in_tensor_ch;
987	                }
988	            }
989	
990	            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
991	            {
992	                pOut =
993	                    nn_mat_mul_kernel_q7_u16_u8_reordered_bias_2sft(ker_weight,
994	                                                                    (u16_t*)in_tmp_buf,
995	                                                                    out_tensor_ch,
996	                                                                    in_tensor_ch * ker_dim * ker_dim,
997	                                                                    pre_rshift,
998	                                                                    out_scale,
999	                                                                    post_rshift,
1000	                                                                    bias,
1001	                                                                    pOut);
1002	                /* counter reset */
1003	                pBuffer = (u16_t*)in_tmp_buf;
1004	            }
1005	        }
1006	    }
1007	
1008	    for (; i_out_y < out_tensor_dim; i_out_y++)
1009	    {
1010	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
1011	        {
1012	            /* This part implements the im2col function */
1013	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
1014	            {
1015	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
1016	                {
1017	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
1018	                    {
1019	                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
1020	                    }
1021	                    else
1022	                    {
1023	                        nn_dup_u8_u16_reordered
1024	                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
1025	                    }
1026	                    pBuffer += in_tensor_ch;
1027	                }
1028	            }
1029	
1030	            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim * ker_dim)
1031	            {
1032	                pOut =
1033	                    nn_mat_mul_kernel_q7_u16_u8_reordered_bias_2sft(ker_weight,
1034	                                                                    (u16_t*)in_tmp_buf,
1035	                                                                    out_tensor_ch,
1036	                                                                    in_tensor_ch * ker_dim * ker_dim,
1037	                                                                    pre_rshift,
1038	                                                                    out_scale,
1039	                                                                    post_rshift,
1040	                                                                    bias,
1041	                                                                    pOut);
1042	                /* counter reset */
1043	                pBuffer = (u16_t*)in_tmp_buf;
1044	            }
1045	        }
1046	    }
1047	
1048	    /* check if there is left-over for compute */
1049	    if (pBuffer != (u16_t*)in_tmp_buf)
1050	    {
1051	        const q7_t *pA = ker_weight;
1052	        int       i;
1053	
1054	        for (i = 0; i < out_tensor_ch; i++)
1055	        {
1056	            q31_t     sum = bias[i];
1057	            u16_t    *pB = (u16_t*)in_tmp_buf;
1058	            /* each time it process 4 entries */
1059	            uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
1060	
1061	            while (colCnt)
1062	            {
1063	                q31_t     inA1, inA2;
1064	                q31_t     inB1, inB2;
1065	
1066	                pA = (q7_t *) read_and_pad_reordered((void *)pA, &inA1, &inA2);
1067	
1068	                inB1 = *__SIMD32(pB)++;
1069	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
1070	                inB2 = *__SIMD32(pB)++;
1071	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
1072	
1073	                colCnt--;
1074	            }
1075	            //since in_tensor_ch is multiple of 4 (input constraints), the
1076	            //following codes will not be reached
1077	            // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
1078	            // while (colCnt)
1079	            // {
1080	            //     q7_t      inA1 = *pA++;
1081	            //     q15_t     inB1 = *pB++;
1082	            //     sum += inA1 * inB1;
1083	            //     colCnt--;
1084	            // }
1085	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1086	            *pOut++ = NDS_DSP_SAT((sum >> post_rshift), 8);
1087	        }
1088	    }
1089	#else
1090	    uint16_t  i, j, k, l, m, n;
1091	    int       conv_out;
1092	    long in_row, in_col;
1093	
1094	    for (i = 0; i < out_tensor_ch; i++)
1095	    {
1096	        for (j = 0; j < out_tensor_dim; j++)
1097	        {
1098	            for (k = 0; k < out_tensor_dim; k++)
1099	            {
1100	                conv_out = bias[i];
1101	                for (m = 0; m < ker_dim; m++)
1102	                {
1103	                    for (n = 0; n < ker_dim; n++)
1104	                    {
1105	                        // if-for implementation
1106	                        in_row = stride * j + m - pad;
1107	                        in_col = stride * k + n - pad;
1108	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
1109	                        {
1110	                            for (l = 0; l < in_tensor_ch; l++)
1111	                            {
1112	                                conv_out +=
1113	                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
1114	                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
1115	                            }
1116	                        }
1117	                    }
1118	                }
1119	                if (conv_out < 0)
1120	                    out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = 0;
1121	                else
1122	                {
1123	                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1124	                    out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SAT((conv_out >> post_rshift), 8);
1125	                }
1126	            }
1127	        }
1128	    }
1129	#endif
1130	#endif  //ENA_EMPTY_FUN
1131	    /* Return to application */
1132	    return 0;
1133	}
