24	//// Convolution Functions
25	#if (NDS_VEC_RVV_VERSION >= 100)
26	u8_t *nn_mat_mul_kernel_u8_bias_2sft_unroll4(const q7_t * src1,
27	                                             const u8_t * src2,
28	                                             const uint16_t out_tensor_ch,
29	                                             const uint16_t col_src1,
30	                                             const uint16_t pre_rshift,
31	                                             const uint16_t out_scale,
32	                                             const uint16_t post_rshift,
33	                                             const q31_t * bias,
34	                                             u8_t * out)
35	{
36	#if defined(ENA_NDS_V5_VEC_DOT_PROD) && (ENA_VEC_INTRINSIC)
37	    unsigned long vl;
38	    unsigned long rowCnt = out_tensor_ch >> 2;
39	    u8_t *pOut2 = out + out_tensor_ch;
40	    u8_t *pOut3 = out + out_tensor_ch * 2;
41	    u8_t *pOut4 = out + out_tensor_ch * 3;
42	
43	    const q7_t *pA = src1;
44	
45	    vl = __riscv_vsetvl_e32m1(1);
46	    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //keep zero for redsum
47	
48	    while(rowCnt > 0)
49	    {
50	        // setup pointers for A
51	        const q7_t *pA2 = pA + col_src1;
52	        const q7_t *pA3 = pA + col_src1 * 2;
53	        const q7_t *pA4 = pA + col_src1 * 3;
54	        // setup pointers for B
55	        const u8_t *pB = src2;
56	        const u8_t *pB2 = pB + col_src1;
57	        const u8_t *pB3 = pB + col_src1 * 2;
58	        const u8_t *pB4 = pB + col_src1 * 3;
59	
60	        vl = __riscv_vsetvlmax_e32m8();
61	
62	        //init
63	        //clear v8~v23 (keep multiplication results)
64	        vint32m8_t vZeroAcc0 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
65	        vint32m8_t vZeroAcc1 = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
66	
67	        vint32m1_t vAcc0 = __riscv_vget_i32m1(vZeroAcc0, 0);
68	        vint32m1_t vAcc1 = __riscv_vget_i32m1(vZeroAcc0, 1);
69	        vint32m1_t vAcc2 = __riscv_vget_i32m1(vZeroAcc0, 2);
70	        vint32m1_t vAcc3 = __riscv_vget_i32m1(vZeroAcc0, 3);
71	        vint32m1_t vAcc4 = __riscv_vget_i32m1(vZeroAcc0, 4);
72	        vint32m1_t vAcc5 = __riscv_vget_i32m1(vZeroAcc0, 5);
73	        vint32m1_t vAcc6 = __riscv_vget_i32m1(vZeroAcc0, 6);
74	        vint32m1_t vAcc7 = __riscv_vget_i32m1(vZeroAcc0, 7);
75	
76	        vint32m1_t vAcc8 = __riscv_vget_i32m1(vZeroAcc1, 0);
77	        vint32m1_t vAcc9 = __riscv_vget_i32m1(vZeroAcc1, 1);
78	        vint32m1_t vAcc10 = __riscv_vget_i32m1(vZeroAcc1, 2);
79	        vint32m1_t vAcc11 = __riscv_vget_i32m1(vZeroAcc1, 3);
80	        vint32m1_t vAcc12 = __riscv_vget_i32m1(vZeroAcc1, 4);
81	        vint32m1_t vAcc13 = __riscv_vget_i32m1(vZeroAcc1, 5);
82	        vint32m1_t vAcc14 = __riscv_vget_i32m1(vZeroAcc1, 6);
83	        vint32m1_t vAcc15 = __riscv_vget_i32m1(vZeroAcc1, 7);
84	
85	        unsigned long colCnt = col_src1;
86	        while(colCnt > 0)
87	        {
88	            vl = __riscv_vsetvl_e8m1(colCnt);
89	            //load src1 and src2
90	            vint8m1_t vpA_i8m1 = __riscv_vle8_v_i8m1(pA, vl);
91	            vint8m1_t vpA2_i8m1 = __riscv_vle8_v_i8m1(pA2, vl);
92	            vint8m1_t vpA3_i8m1 = __riscv_vle8_v_i8m1(pA3, vl);
93	            vint8m1_t vpA4_i8m1 = __riscv_vle8_v_i8m1(pA4, vl);
94	
95	            vuint8m1_t vpB_u8m1 = __riscv_vle8_v_u8m1(pB, vl);
96	            vuint8m1_t vpB2_u8m1 = __riscv_vle8_v_u8m1(pB2, vl);
97	            vuint8m1_t vpB3_u8m1 = __riscv_vle8_v_u8m1(pB3, vl);
98	            vuint8m1_t vpB4_u8m1 = __riscv_vle8_v_u8m1(pB4, vl);
99	
100	            //bump pointers and update loop counter
101	            colCnt -= vl;
102	            pA += vl;
103	            pA2 += vl;
104	            pA3 += vl;
105	            pA4 += vl;
106	            pB += vl;
107	            pB2 += vl;
108	            pB3 += vl;
109	            pB4 += vl;
110	
111	            //set the proper avl/SEW/LMUL values for vd4dot
112	            vl >>= 2;
113	
114	            // //acc += src1 * src2
115	            vl = __riscv_vsetvl_e32m1(vl);
116	
117	            //acc += src1 * src2
118	            vAcc0 = __riscv_vd4dotsu_vv_i32m1(vAcc0, vpA_i8m1, vpB_u8m1, vl);
119	            vAcc1 = __riscv_vd4dotsu_vv_i32m1(vAcc1, vpA2_i8m1, vpB_u8m1, vl);
120	            vAcc2 = __riscv_vd4dotsu_vv_i32m1(vAcc2, vpA3_i8m1, vpB_u8m1, vl);
121	            vAcc3 = __riscv_vd4dotsu_vv_i32m1(vAcc3, vpA4_i8m1, vpB_u8m1, vl);
122	
123	            vAcc4 = __riscv_vd4dotsu_vv_i32m1(vAcc4, vpA_i8m1, vpB2_u8m1, vl);
124	            vAcc5 = __riscv_vd4dotsu_vv_i32m1(vAcc5, vpA2_i8m1, vpB2_u8m1, vl);
125	            vAcc6 = __riscv_vd4dotsu_vv_i32m1(vAcc6, vpA3_i8m1, vpB2_u8m1, vl);
126	            vAcc7 = __riscv_vd4dotsu_vv_i32m1(vAcc7, vpA4_i8m1, vpB2_u8m1, vl);
127	
128	            vAcc8 = __riscv_vd4dotsu_vv_i32m1(vAcc8, vpA_i8m1, vpB3_u8m1, vl);
129	            vAcc9 = __riscv_vd4dotsu_vv_i32m1(vAcc9, vpA2_i8m1, vpB3_u8m1, vl);
130	            vAcc10 = __riscv_vd4dotsu_vv_i32m1(vAcc10, vpA3_i8m1, vpB3_u8m1, vl);
131	            vAcc11 = __riscv_vd4dotsu_vv_i32m1(vAcc11, vpA4_i8m1, vpB3_u8m1, vl);
132	
133	            vAcc12 = __riscv_vd4dotsu_vv_i32m1(vAcc12, vpA_i8m1, vpB4_u8m1, vl);
134	            vAcc13 = __riscv_vd4dotsu_vv_i32m1(vAcc13, vpA2_i8m1, vpB4_u8m1, vl);
135	            vAcc14 = __riscv_vd4dotsu_vv_i32m1(vAcc14, vpA3_i8m1, vpB4_u8m1, vl);
136	            vAcc15 = __riscv_vd4dotsu_vv_i32m1(vAcc15, vpA4_i8m1, vpB4_u8m1, vl);
137	        }
138	        pA = pA4;
139	
140	        vl = __riscv_vsetvl_e32m1(col_src1);;    //note the avl here
141	        vint32m1_t vSum0 = __riscv_vredsum(vAcc0, vZero, vl);
142	        vint32m1_t vSum1 = __riscv_vredsum(vAcc1, vZero, vl);
143	        vint32m1_t vSum2 = __riscv_vredsum(vAcc2, vZero, vl);
144	        vint32m1_t vSum3 = __riscv_vredsum(vAcc3, vZero, vl);
145	
146	        vint32m1_t vSum4 = __riscv_vredsum(vAcc4, vZero, vl);
147	        vint32m1_t vSum5 = __riscv_vredsum(vAcc5, vZero, vl);
148	        vint32m1_t vSum6 = __riscv_vredsum(vAcc6, vZero, vl);
149	        vint32m1_t vSum7 = __riscv_vredsum(vAcc7, vZero, vl);
150	
151	        vint32m1_t vSum8 = __riscv_vredsum(vAcc8, vZero, vl);
152	        vint32m1_t vSum9 = __riscv_vredsum(vAcc9, vZero, vl);
153	        vint32m1_t vSum10 = __riscv_vredsum(vAcc10, vZero, vl);
154	        vint32m1_t vSum11 = __riscv_vredsum(vAcc11, vZero, vl);
155	
156	        vint32m1_t vSum12 = __riscv_vredsum(vAcc12, vZero, vl);
157	        vint32m1_t vSum13 = __riscv_vredsum(vAcc13, vZero, vl);
158	        vint32m1_t vSum14 = __riscv_vredsum(vAcc14, vZero, vl);
159	        vint32m1_t vSum15 = __riscv_vredsum(vAcc15, vZero, vl);
160	
161	        vl = __riscv_vsetvl_e32m1(4);     //4: 4 acc
162	        vSum0 = __riscv_vslideup(vSum0, vSum1, 1, vl);
163	        vSum0 = __riscv_vslideup(vSum0, vSum2, 2, vl);
164	        vSum0 = __riscv_vslideup(vSum0, vSum3, 3, vl);
165	
166	        vSum4 = __riscv_vslideup(vSum4, vSum5, 1, vl);
167	        vSum4 = __riscv_vslideup(vSum4, vSum6, 2, vl);
168	        vSum4 = __riscv_vslideup(vSum4, vSum7, 3, vl);
169	
170	        vSum8 = __riscv_vslideup(vSum8, vSum9, 1, vl);
171	        vSum8 = __riscv_vslideup(vSum8, vSum10, 2, vl);
172	        vSum8 = __riscv_vslideup(vSum8, vSum11, 3, vl);
173	
174	        vSum12 = __riscv_vslideup(vSum12, vSum13, 1, vl);
175	        vSum12 = __riscv_vslideup(vSum12, vSum14, 2, vl);
176	        vSum12 = __riscv_vslideup(vSum12, vSum15, 3, vl);
177	
178	        //load bias
179	        vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
180	        bias += vl;
181	
182	        //add bias to acc
183	        vSum0 = __riscv_vadd(vSum0, vBias, vl);
184	        vSum4 = __riscv_vadd(vSum4, vBias, vl);
185	        vSum8 = __riscv_vadd(vSum8, vBias, vl);
186	        vSum12 = __riscv_vadd(vSum12, vBias, vl);
187	
188	        //1st shift of 2-stage shift
189	        vSum0 = __riscv_vsra(vSum0, pre_rshift, vl);
190	        vSum4 = __riscv_vsra(vSum4, pre_rshift, vl);
191	        vSum8 = __riscv_vsra(vSum8, pre_rshift, vl);
192	        vSum12 = __riscv_vsra(vSum12, pre_rshift, vl);
193	
194	        vSum0 = __riscv_vmul(vSum0, out_scale, vl);
195	        vSum4 = __riscv_vmul(vSum4, out_scale, vl);
196	        vSum8 = __riscv_vmul(vSum8, out_scale, vl);
197	        vSum12 = __riscv_vmul(vSum12, out_scale, vl);
198	
199	        vSum0 = __riscv_vadd(vSum0, NN_ROUND(post_rshift), vl);
200	        vSum4 = __riscv_vadd(vSum4, NN_ROUND(post_rshift), vl);
201	        vSum8 = __riscv_vadd(vSum8, NN_ROUND(post_rshift), vl);
202	        vSum12 = __riscv_vadd(vSum12, NN_ROUND(post_rshift), vl);
203	
204	        //saturate into 8-bits
205	        vSum0 = __riscv_vmax(vSum0, 0, vl);
206	        vSum4 = __riscv_vmax(vSum4, 0, vl);
207	        vSum8 = __riscv_vmax(vSum8, 0, vl);
208	        vSum12 = __riscv_vmax(vSum12, 0, vl);
209	        vl = __riscv_vsetvl_e16mf2(4);     //4: 4 acc
210	        vint16mf2_t vSum0_i16mf2 = __riscv_vnsra(vSum0, post_rshift, vl);
211	        vint16mf2_t vSum4_i16mf2 = __riscv_vnsra(vSum4, post_rshift, vl);
212	        vint16mf2_t vSum8_i16mf2 = __riscv_vnsra(vSum8, post_rshift, vl);
213	        vint16mf2_t vSum12_i16mf2 = __riscv_vnsra(vSum12, post_rshift, vl);
214	        vl = __riscv_vsetvl_e8mf4(4);     //4: 4 acc
215	        vuint16mf2_t vSum0_u16mf2 = __riscv_vreinterpret_u16mf2(vSum0_i16mf2);
216	        vuint8mf4_t vSum0_u8mf4 = __riscv_vnclipu(vSum0_u16mf2, 0, __RISCV_VXRM_RNU, vl);
217	        vuint16mf2_t vSum4_u16mf2 = __riscv_vreinterpret_u16mf2(vSum4_i16mf2);
218	        vuint8mf4_t vSum4_u8mf4 = __riscv_vnclipu(vSum4_u16mf2, 0, __RISCV_VXRM_RNU, vl);
219	        vuint16mf2_t vSum8_u16mf2 = __riscv_vreinterpret_u16mf2(vSum8_i16mf2);
220	        vuint8mf4_t vSum8_u8mf4 = __riscv_vnclipu(vSum8_u16mf2, 0, __RISCV_VXRM_RNU, vl);
221	        vuint16mf2_t vSum12_u16mf2 = __riscv_vreinterpret_u16mf2(vSum12_i16mf2);
222	        vuint8mf4_t vSum12_u8mf4 = __riscv_vnclipu(vSum12_u16mf2, 0, __RISCV_VXRM_RNU, vl);
223	
